exercises.solution_code:
#include <iostream>

int main() {
    int n{};
    std::cin >> n;

    if (n < 0)
        std::cout << "negative\n";
    else if (n == 0)
        std::cout << "zero\n";
    else
        std::cout << "positive\n";

    return 0;
}

