exercises.solution_code:
#include <iostream>

int main() {
    int a{}, b{}, c{};
    std::cin >> a >> b >> c;

    // Find minimum
    int min{};
    if (a <= b && a <= c)
        min = a;
    else if (b <= a && b <= c)
        min = b;
    else
        min = c;

    // Find maximum
    int max{};
    if (a >= b && a >= c)
        max = a;
    else if (b >= a && b >= c)
        max = b;
    else
        max = c;

    std::cout << "Min: " << min << '\n';
    std::cout << "Max: " << max << '\n';

    return 0;
}
